class Solution {
public:
    int numSub(string s) {
        long long count = 0;
        long long mod = 1e9 + 7;
        int currentCount = 0;
        for (char c : s) {
            if (c == '1') {
                currentCount++;
                count = (count + currentCount) % mod;
            }
        }
        return count;
    }
};
